patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..0078a0ebb0ce 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1871,7 +1871,32 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
         Ctlz, "", /*HasNUW*/ true, /*HasNSW*/ true);
     return replaceInstUsesWith(I, Builder.CreateZExtOrTrunc(Ret, I.getType()));
   }
-
+  // Fold the ceil division by power of two idiom:
+  // (X >> C) + ((X & ((1 << C) - 1)) != 0) --> (X + ((1 << C) - 1)) >> C
+  Value *X;
+  const APInt *C, *Mask;
+  Instruction *LShr, *ZExt;
+  if (match(&I, m_c_Add(m_CombineAnd(m_OneUse(m_LShr(m_Value(X), m_APInt(C))),
+                                     m_Instruction(LShr)),
+                        m_CombineAnd(m_ZExt(m_OneUse(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                                           m_OneUse(m_And(m_Deferred(X),
+                                                                          m_APInt(Mask))),
+                                                           m_Zero()))),
+                                     m_Instruction(ZExt))))) {
+    // Check that Mask is (1 << C) - 1
+    if (C->ult(X->getType()->getScalarSizeInBits()) &&
+        *Mask == APInt::getLowBitsSet(C->getBitWidth(), C->getZExtValue())) {
+      // Ensure that X + Mask does not overflow.
+      Constant *MaskC = ConstantInt::get(X->getType(), *Mask);
+      bool NoUnsignedOverflow = willNotOverflowUnsignedAdd(X, MaskC, I);
+      bool NoSignedOverflow = willNotOverflowSignedAdd(X, MaskC, I);
+      if (NoUnsignedOverflow) {
+        Value *Add = Builder.CreateAdd(X, MaskC, "", NoUnsignedOverflow, NoSignedOverflow);
+        Value *NewLShr = Builder.CreateLShr(Add, *C);
+        return replaceInstUsesWith(I, NewLShr);
+      }
+    }
+  }
   if (Instruction *Res = foldSquareSumInt(I))
     return Res;

